class Solution {
public:
    int removeDuplicates(const vector<int>& nums) {
        vector<int> unique;
        for (int i = 0; i < nums.size(); i++) {
            bool found = false;
            for (int j = 0; j < unique.size(); j++) {
                if (nums[i] == unique[j]) {
                    found = true;
                    break;
                }
            }
            if (!found) {
                unique.push_back(nums[i]);
            }
        }
        return unique.size();
    }
